# Look at the cipher/keys tables
for t in ['cipher', '_cipher', 'item', 'collection']:
    try:
        cols = conn.execute(f'PRAGMA table_info({t})').fetchall()
        if cols:
            print(f'\n{t} columns:', [(c[1], c[2]) for c in cols])
            rows = conn.execute(f'SELECT * FROM {t} LIMIT 3').fetchall()
            print(f'{t} rows:', len(rows))
            for r in rows:
                print(f'  {r[:5]}...')
    except Exception as e:
        print(f'{t}: {e}')
conn.close()
" 2>&1"}

