import sqlite3, json
conn = sqlite3.connect('/tmp/vw-db.sqlite3')
rows = conn.execute('SELECT uuid, atype, name, data FROM ciphers').fetchall()
for r in rows:
    uuid, atype, name, data = r
    print(f'UUID={uuid}, type={atype}, name={name}')
    if data:
        try:
            parsed = json.loads(data)
            print(f'  data: {json.dumps(parsed, indent=2)[:500]}')
        except:
            print(f'  data: {data[:200]}')
    print()
conn.close()
" 2>&1"}

